import React, {useEffect, useState} from "react";
import styled, {keyframes} from 'styled-components';
import {slideOutUp,slideOutDown} from 'react-animations';


const Cover = () => {
    const SlideOutUp = styled.div`animation: 2s ${keyframes`${slideOutUp}`} 1 `;
    const SlideOutDown = styled.div`animation: 2s ${keyframes`${slideOutDown}`} 1 `;
    const [isButtonClicked,SetButtonClick] = useState(
        {
            web:false,
            software:false,
            transition:false
        }
    );

    useEffect(()=>{
        if(isButtonClicked.web===true)
        {

            // alert("WEB")
        } else if(isButtonClicked.software===true)
        {
            // alert("SOFTWARE")
        }
    });

    return (
        <div className="ui segments">
            {isButtonClicked.transition  && (
                <SlideOutUp>
                    <div className="ui segment grid-top top-cover"/>
                </SlideOutUp>
            )
            }
            {!isButtonClicked.transition && (
                <div className="ui segment grid-top top-cover"/>
            )
            }
            <div className="ui segment choices" style={{border:'none'}}>
                <h1 className="ui header">You would like me to be..</h1>
                <button
                    className="circular ui grid-wrap inverted right labeled icon purple button"
                    onClick={()=>SetButtonClick({web:true,transition:true})}
                    style={{height:'5vh',fontSize:"1em"}}
                ><i className="right arrow icon"></i>Front/Back-end Developer</button>
                <button
                    className="circular ui inverted right labeled icon purple button"
                    onClick={()=>SetButtonClick({software:true,transition:true})}
                    style={{height:'5vh',fontSize:"1em"}}
                ><i className="right arrow icon"></i>Software Engineer</button>
            </div>
            {isButtonClicked.transition && (
                <SlideOutDown className="bottom-cover-div">
                    <div className="ui segment grid-bottom bottom-cover"></div>
                </SlideOutDown>
            )
            }
            {!isButtonClicked.transition && (
                <div className="bottom-cover-div">
                    <div className="ui segment grid-bottom bottom-cover"></div>
                </div>
            )
            }
        </div>
    )
};
export default Cover;
